#include<bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=2e5+5;
int n,m,s,w[MAXN],v[MAXN],sum1[MAXN],sum2[MAXN],ql[MAXN],qr[MAXN],k;
bool check(int x)
{
    cl(sum1);
    cl(sum2);
    int ans=0;
    FOR(i,1,n)
    {
        sum1[i]=sum1[i-1]+(w[i]>=x);
        sum2[i]=sum2[i-1]+(w[i]>=x)*v[i];
    }
    FOR(i,1,m)
    {
        int cnt=sum1[qr[i]]-sum1[ql[i]-1];
        int val=sum2[qr[i]]-sum2[ql[i]-1];
        ans+=cnt*val;
    }
    k=ans;
    return ans>s;
}
signed main(void)
{
    n=read(),m=read(),s=read();
    FOR(i,1,n)w[i]=read(),v[i]=read();
    FOR(i,1,m)ql[i]=read(),qr[i]=read();
    int ans=s,l=1,r=1e8;
    wh(l<=r)
    {
        if(check(mid))l=mid+1;
        else r=mid-1;
        ans=min(ans,abs(s-k));
    }
    write(ans);
    return false;
}
